document.addEventListener('DOMContentLoaded', () => {
  const prefersReduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  requestAnimationFrame(() => document.body.classList.add('page-ready'));

  const loader = document.querySelector('.site-loader');
  if (loader) {
    const hideLoader = () => {
      loader.classList.add('is-hidden');
      window.setTimeout(() => loader.remove(), 650);
    };
    window.setTimeout(hideLoader, prefersReduced ? 80 : 420);
  }

  const menuToggle = document.querySelector('[data-menu-toggle]');
  const menu = document.querySelector('[data-menu]');
  if (menuToggle && menu) {
    menuToggle.addEventListener('click', () => {
      const open = menu.classList.toggle('is-open');
      menuToggle.setAttribute('aria-expanded', String(open));
      document.body.classList.toggle('is-locked', open);
    });
    menu.querySelectorAll('a').forEach((link) => {
      link.addEventListener('click', () => {
        menu.classList.remove('is-open');
        menuToggle.setAttribute('aria-expanded', 'false');
        document.body.classList.remove('is-locked');
      });
    });
  }

  document.querySelectorAll('[data-nav-dropdown]').forEach((dropdown) => {
    const toggle = dropdown.querySelector('[data-submenu-toggle]');
    if (!toggle) return;
    toggle.addEventListener('click', () => {
      const open = dropdown.classList.toggle('is-open');
      toggle.setAttribute('aria-expanded', String(open));
    });
  });

  const modal = document.querySelector('[data-inquiry-modal]');
  const openers = document.querySelectorAll('[data-open-inquiry]');
  const closers = document.querySelectorAll('[data-close-inquiry]');
  const toggleModal = (open) => {
    if (!modal) return;
    modal.hidden = !open;
    document.body.classList.toggle('is-locked', open);
  };
  openers.forEach((btn) => btn.addEventListener('click', () => toggleModal(true)));
  closers.forEach((btn) => btn.addEventListener('click', () => toggleModal(false)));
  document.addEventListener('keydown', (event) => {
    if (event.key === 'Escape') toggleModal(false);
  });

  const revealTargets = document.querySelectorAll('.reveal, .section-divider');
  if (prefersReduced) {
    revealTargets.forEach((item) => item.classList.add('is-visible'));
  } else {
    const observer = new IntersectionObserver((entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          entry.target.classList.add('is-visible');
          observer.unobserve(entry.target);
        }
      });
    }, { threshold: 0.16 });
    revealTargets.forEach((item) => observer.observe(item));
  }

  document.querySelectorAll('[data-counter]').forEach((counter) => {
    const target = Number(counter.getAttribute('data-counter') || 0);
    const suffix = counter.textContent.trim().includes('+') ? '+' : '+';
    if (prefersReduced) {
      counter.textContent = `${target}${suffix}`;
      return;
    }
    const run = () => {
      const duration = 1200;
      const startTime = performance.now();
      const step = (now) => {
        const progress = Math.min((now - startTime) / duration, 1);
        const current = Math.round(target * progress);
        counter.textContent = `${current}${suffix}`;
        if (progress < 1) requestAnimationFrame(step);
      };
      requestAnimationFrame(step);
    };
    const observer = new IntersectionObserver((entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          run();
          observer.disconnect();
        }
      });
    }, { threshold: 0.4 });
    observer.observe(counter);
  });

  const hero = document.querySelector('[data-hero-rotator]');
  if (hero) {
    const primary = hero.querySelector('.hero-backdrop-primary');
    const secondary = hero.querySelector('.hero-backdrop-secondary');
    const linksWrap = hero.querySelector('[data-hero-links]');
    const eyebrow = hero.querySelector('[data-hero-eyebrow]');
    const caption = hero.querySelector('[data-hero-caption]');
    const dotsWrap = hero.querySelector('[data-hero-dots]');
    const prev = hero.querySelector('[data-hero-prev]');
    const next = hero.querySelector('[data-hero-next]');
    const slides = JSON.parse(hero.getAttribute('data-hero-slides') || '[]');
    let index = 0;
    let activePrimary = true;
    let timer = null;

    const renderSlide = (newIndex) => {
      if (!slides.length || !primary || !secondary || !linksWrap || !eyebrow || !caption || !dotsWrap) return;
      const slide = slides[newIndex];
      const incoming = activePrimary ? secondary : primary;
      const outgoing = activePrimary ? primary : secondary;
      incoming.style.backgroundImage = `linear-gradient(115deg,rgba(11,26,43,.78),rgba(19,48,79,.46)),url('${slide.image}')`;
      incoming.classList.add('is-active');
      outgoing.classList.remove('is-active');
      activePrimary = !activePrimary;
      eyebrow.textContent = slide.eyebrow;
      caption.textContent = slide.caption;
      linksWrap.innerHTML = slide.links.map((link) => `<a class="hero-link" href="${link.href}">${link.label}</a>`).join('');
      dotsWrap.querySelectorAll('.hero-dot').forEach((dot, dotIndex) => {
        dot.classList.toggle('is-active', dotIndex === newIndex);
        dot.setAttribute('aria-pressed', String(dotIndex === newIndex));
      });
      index = newIndex;
    };

    if (slides.length) {
      dotsWrap.innerHTML = slides.map((_, dotIndex) => `<button type="button" class="hero-dot${dotIndex === 0 ? ' is-active' : ''}" data-hero-dot="${dotIndex}" aria-label="Go to slide ${dotIndex + 1}" aria-pressed="${dotIndex === 0 ? 'true' : 'false'}"></button>`).join('');
      renderSlide(0);
      const goTo = (newIndex) => {
        const total = slides.length;
        const wrapped = (newIndex + total) % total;
        renderSlide(wrapped);
      };
      dotsWrap.addEventListener('click', (event) => {
        const target = event.target;
        if (!(target instanceof HTMLElement)) return;
        const dotIndex = target.getAttribute('data-hero-dot');
        if (dotIndex === null) return;
        goTo(Number(dotIndex));
        restart();
      });
      prev?.addEventListener('click', () => {
        goTo(index - 1);
        restart();
      });
      next?.addEventListener('click', () => {
        goTo(index + 1);
        restart();
      });

      const start = () => {
        if (prefersReduced || slides.length < 2) return;
        timer = window.setInterval(() => goTo(index + 1), 4800);
      };
      const stop = () => {
        if (timer) window.clearInterval(timer);
      };
      const restart = () => {
        stop();
        start();
      };
      hero.addEventListener('mouseenter', stop);
      hero.addEventListener('mouseleave', start);
      start();
    }
  }

  document.querySelectorAll('[data-mail-form]').forEach((form) => {
    form.addEventListener('submit', (event) => {
      event.preventDefault();
      if (!(form instanceof HTMLFormElement)) return;
      const status = form.querySelector('.form-status');
      const messageField = form.querySelector('textarea[name="message"]');
      if (messageField instanceof HTMLTextAreaElement && messageField.value.trim().length < 12) {
        messageField.setCustomValidity('Please enter at least 12 characters so we can understand your inquiry.');
      } else if (messageField instanceof HTMLTextAreaElement) {
        messageField.setCustomValidity('');
      }
      if (!form.reportValidity()) return;

      const data = new FormData(form);
      const name = (data.get('name') || '').toString().trim();
      const email = (data.get('email') || '').toString().trim();
      const phone = (data.get('phone') || '').toString().trim();
      const message = (data.get('message') || '').toString().trim();

      const body = [
        'Tropex Website Inquiry',
        `Name: ${name}`,
        `Email: ${email}`,
        `Phone: ${phone || 'N/A'}`,
        '',
        'Message:',
        message
      ].join('\n');

      const whatsappUrl = `https://wa.me/85256864074?text=${encodeURIComponent(body)}`;
      const emailUrl = `mailto:info@tropexltdchina.com?subject=${encodeURIComponent('Tropex Website Inquiry')}&body=${encodeURIComponent(body)}`;

      window.open(whatsappUrl, '_blank', 'noopener');
      if (status) {
        status.innerHTML = `WhatsApp opened with your inquiry. If needed, use <a href="${emailUrl}">email fallback</a>.`;
      }
      form.reset();
    });
  });
});
